#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>

int main() {
    pid_t pid;  // Process ID type

    printf("Parent Process: PID = %d\n", getpid());

    // System call: fork() creates new process
    pid = fork();

    if (pid < 0) {
        // Error occurred
        fprintf(stderr, "Fork failed\n");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child Process: PID = %d, Parent PID = %d\n", 
               getpid(), getppid());

        // System call: execl() replaces process image
        execlp("/bin/ls", "ls", "-l", NULL);
    }
    else {
        // Parent process waits
        wait(NULL);
        printf("Child completed\n");
    }

    return 0;
}

