    LOAD_PROGRAM(programPath, pcb.memorySegment)

    // Step 4: Initialize PCB fields
    pcb.programCounter = ENTRY_POINT
    pcb.stackPointer = STACK_BASE
    pcb.registerValues = 0
    pcb.fileDescriptors = PARENT_FD_LIST
    pcb.parentProcess = CURRENT_PROCESS

    // Step 5: Set process state to READY
    pcb.state = READY

    // Step 6: Add to ready queue
    ADD_TO_READY_QUEUE(pcb)

    // Step 7: Return process ID to parent
    RETURN pcb.processId
END

public class ProcessDemo {
    public static void main(String[] args) {
        try {
            // Get runtime instance (system call to OS)
            Runtime runtime = Runtime.getRuntime();

            // System call: exec() - starts new process
            Process notepad = runtime.exec("notepad.exe");

            System.out.println("Process started: " + notepad.isAlive());

            // Wait for 5 seconds
            Thread.sleep(5000);

            // Destroy the process
            notepad.destroy();

            System.out.println("Process destroyed");

            // Another example: running command
            Process ls = runtime.exec("cmd /c dir");

            // Get input stream (system call for I/O)
            java.io.InputStream in = ls.getInputStream();
            int data;
            while ((data = in.read()) != -1) {
                System.out.print((char) data);
            }

            // Wait for process completion
            int exitCode = ls.waitFor();
            System.out.println("Exit code: " + exitCode);

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
